// SPEC QFLUSH QS3 — control.ts
// Rôle : API interne pour piloter le superviseur.
export function qsStatus(state) {
    return state.list();
}
export function qsStop(state, name) {
    const info = state.get(name);
    if (!info || !info.pid)
        return false;
    try {
        process.kill(info.pid);
        state.update(name, { state: 'stopped', pid: null });
        return true;
    }
    catch (e) {
        return false;
    }
}
